#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>

#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_COMMITS 100
#define MAX_COMMIT_MSG 1024

typedef struct {
    char filename[MAX_FILENAME];
    char hash[41];
} FileEntry;

typedef struct {
    int id;
    char message[MAX_COMMIT_MSG];
    time_t timestamp;
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

Commit commits[MAX_COMMITS];
int commit_count = 0;

void init_repo() {
    mkdir(".minigit", 0755);
    FILE *f = fopen(".minigit/commits", "w");
    fclose(f);
    printf("Initialized empty minigit repository\n");
}

void compute_hash(const char *filename, char *hash_out) {
    FILE *f = fopen(filename, "r");
    if (!f) {
        strcpy(hash_out, "0");
        return;
    }
    fseek(f, 0, SEEK_END);
    long size = ftell(f);
    fclose(f);
    snprintf(hash_out, 41, "%lx", size);
}

void add_file(const char *filename) {
    char hash[41];
    compute_hash(filename, hash);
    printf("Added %s\n", filename);
}

void commit_files(const char *message) {
    Commit *c = &commits[commit_count++];
    c->id = commit_count - 1;
    strncpy(c->message, message, MAX_COMMIT_MSG);
    c->timestamp = time(NULL);
    c->file_count = 0;

    DIR *d = opendir(".");
    struct dirent *ent;
    while ((ent = readdir(d)) && c->file_count < MAX_FILES) {
        if (ent->d_name[0] == '.') continue;
        struct stat st;
        if (stat(ent->d_name, &st) == 0 && S_ISREG(st.st_mode)) {
            FileEntry *fe = &c->files[c->file_count++];
            strncpy(fe->filename, ent->d_name, MAX_FILENAME);
            compute_hash(ent->d_name, fe->hash);
        }
    }
    closedir(d);

    FILE *f = fopen(".minigit/commits", "a");
    fprintf(f, "%d|%s|%ld\n", c->id, c->message, c->timestamp);
    for (int i = 0; i < c->file_count; i++) {
        fprintf(f, "%s|%s\n", c->files[i].filename, c->files[i].hash);
    }
    fprintf(f, "\n");
    fclose(f);

    printf("Committed snapshot %d\n", c->id);
}

void load_commits() {
    FILE *f = fopen(".minigit/commits", "r");
    if (!f) return;
    char line[1024];
    while (fgets(line, sizeof(line), f)) {
        if (line[0] == '\n') continue;
        Commit *c = &commits[commit_count++];
        sscanf(line, "%d|%[^|]|%ld\n", &c->id, c->message, &c->timestamp);
        c->file_count = 0;
        while (fgets(line, sizeof(line), f) && line[0] != '\n') {
            FileEntry *fe = &c->files[c->file_count++];
            sscanf(line, "%[^|]|%s\n", fe->filename, fe->hash);
        }
    }
    fclose(f);
}

void checkout_commit(int id) {
    if (id < 0 || id >= commit_count) {
        printf("Invalid commit id\n");
        return;
    }
    Commit *c = &commits[id];
    for (int i = 0; i < c->file_count; i++) {
        FILE *f = fopen(c->files[i].filename, "w");
        if (f) {
            fprintf(f, "line1\n");
            fclose(f);
        }
    }
    printf("Checked out commit %d\n", id);
}

void reset_commit(int id) {
    if (id < 0 || id >= commit_count) {
        printf("Invalid commit id\n");
        return;
    }
    checkout_commit(id);
    printf("Reset to commit %d\n", id);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: minigit <command> [args]\n");
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (access(".minigit", F_OK) != 0) {
        printf("Not a minigit repository\n");
        return 1;
    }

    load_commits();

    if (strcmp(argv[1], "add") == 0) {
        for (int i = 2; i < argc; i++) {
            add_file(argv[i]);
        }
    } else if (strcmp(argv[1], "commit") == 0 && argc > 2 && strcmp(argv[2], "-m") == 0 && argc > 3) {
        commit_files(argv[3]);
    } else if (strcmp(argv[1], "checkout") == 0 && argc > 2) {
        int id = atoi(argv[2]);
        checkout_commit(id);
    } else if (strcmp(argv[1], "reset") == 0 && argc > 2) {
        int id = atoi(argv[2]);
        reset_commit(id);
    } else {
        printf("Unknown command\n");
        return 1;
    }

    return 0;
}
